// ─────────────────────────────────────────────────────────────
// CHECK IF TODAY'S DAILY NOTE ALREADY EXISTS
// Looks for a file named YYYY-MM-DD.md in the daily notes folder.
// ─────────────────────────────────────────────────────────────
const fs = require('fs');
const path = require('path');

const vaultPath = $env.OBSIDIAN_VAULT_PATH || 'C:/Users/Admin/Desktop/Desktop Folders/Obsidian/Homelab';

const now = new Date();
const year = now.getFullYear();
const month = String(now.getMonth() + 1).padStart(2, '0');
const day = String(now.getDate()).padStart(2, '0');
const dateStr = `${year}-${month}-${day}`;

// Daily notes location
const dailyNotesDir = path.join(vaultPath, '40_Timeline_Weekly');
const dailyNoteFile = path.join(dailyNotesDir, `${dateStr}.md`);

const exists = fs.existsSync(dailyNoteFile);

// Compute day-of-week name
const dayNames = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
const dayName = dayNames[now.getDay()];

// Compute ISO week number
const janFirst = new Date(year, 0, 1);
const dayOfYear = Math.ceil((now.getTime() - janFirst.getTime()) / 86400000);
const weekNumber = Math.ceil((dayOfYear + janFirst.getDay()) / 7);
const weekStr = `${year}-W${String(weekNumber).padStart(2, '0')}`;

return [{
  json: {
    exists,
    dateStr,
    dayName,
    weekStr,
    dailyNoteFile,
    dailyNotesDir,
    vaultPath
  }
}];

// ─────────────────────────────────────────────────────────────
// CREATE THE DAILY NOTE
// Generates the daily note with frontmatter and standard sections
// matching the vault's Daily Note template format.
// ─────────────────────────────────────────────────────────────
const fs = require('fs');
const path = require('path');

const { dateStr, dayName, weekStr, dailyNoteFile, dailyNotesDir } = $input.item.json;

// Ensure directory exists
if (!fs.existsSync(dailyNotesDir)) {
  fs.mkdirSync(dailyNotesDir, { recursive: true });
}

// Determine focus theme based on day of week
const focusThemes = {
  'Monday': 'Planning & Priorities',
  'Tuesday': 'Deep Work',
  'Wednesday': 'Collaboration & Meetings',
  'Thursday': 'Deep Work',
  'Friday': 'Review & Wrap-Up',
  'Saturday': 'Personal & Projects',
  'Sunday': 'Rest & Reflection'
};
const focusTheme = focusThemes[dayName] || 'General';

const content = `---
date: ${dateStr}
day: ${dayName}
week: ${weekStr}
focus_theme: "${focusTheme}"
tags:
  - daily-note
---

# ${dayName}, ${dateStr}

> **Focus Theme:** ${focusTheme}

---

## Top 3 Priorities

- [ ] 
- [ ] 
- [ ] 

---

## Tasks Captured



---

## Notes



---

## End of Day

**What went well today?**


**What could be improved?**


**Carry forward to tomorrow:**

- [ ] 
`;

try {
  fs.writeFileSync(dailyNoteFile, content, 'utf8');
  return [{
    json: {
      success: true,
      file: dailyNoteFile,
      dateStr,
      dayName,
      weekStr,
      focusTheme,
      message: `Daily note created: ${dateStr}.md`
    }
  }];
} catch (err) {
  return [{
    json: {
      success: false,
      file: dailyNoteFile,
      dateStr,
      error: true,
      errorMessage: `Failed to create daily note: ${err.message}`
    }
  }];
}

// ─────────────────────────────────────────────────────────────
// LOG: NOTE ALREADY EXISTS
// Logs that the daily note was already present — no action taken.
// ─────────────────────────────────────────────────────────────
const { dateStr, dailyNoteFile } = $input.item.json;

console.log(`Daily note already exists for ${dateStr}, skipping creation.`);

return [{
  json: {
    success: true,
    skipped: true,
    file: dailyNoteFile,
    dateStr,
    message: `Daily note already exists: ${dateStr}.md — no action taken`
  }
}];

// ─────────────────────────────────────────────────────────────
// COMPLETION SUMMARY
// Logs the final result of the daily note creation attempt.
// ─────────────────────────────────────────────────────────────
const item = $input.item.json;

const summary = {
  timestamp: new Date().toISOString(),
  dateStr: item.dateStr,
  file: item.file,
  created: !item.skipped && item.success && !item.error,
  skipped: item.skipped || false,
  error: item.error || false,
  message: item.message || item.errorMessage || 'Unknown'
};

console.log(`Daily Note Creator: ${summary.message}`);

return [{ json: summary }];
